import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Scanner;

public class Crypto {
	/**
	 * Defining the modulo
	 */
	static int MODULO = 1000000007;

	public static void main(String[] args) throws IOException {
		// Reading the inputs
		File inputFile = new File("crypto.in");
		Scanner scanner = new Scanner(inputFile);

		// Reading the number of targets and the maximum
		// number of operations
		final int N = scanner.nextInt();
		final int L = scanner.nextInt();
		scanner.nextLine();

		// Reading the key and the substring S
		String K = scanner.nextLine();
		String S = scanner.nextLine();
		scanner.close();

		// Remembering how many characters are in the key
		// excepting the '?' character
		ArrayList<Character> chars = new ArrayList<>();
		for (int i = 0; i < L; i++) {
			if ((! chars.contains(S.charAt(i)))) {
				chars.add(S.charAt(i));
			}
		}

		// Creating a matrix of N lines and L columns to calculate
		// the number of appearances of S in the key
		int[][] dpm = new int[N + 1][L + 1];
		dpm[0][0] = 1;

		// Filling the first column
		int numSub = 1;
		int size = chars.size();

		for (int i = 1; i <= N; i++) {
			// If we found a '?' character we need to multiply
			// the numSub by size, but as the numbers can get
			// very big, after each addition, we need to apply the MODULO
			if (K.charAt(i - 1) == '?' && size != 0) {
				int sumSub = 0;
				for (int k = 0; k < size; k++) {
					sumSub = (sumSub + numSub) % MODULO;
				}
				numSub = sumSub;
			}

			// The given size is put on the position
			dpm[i][0] = numSub;
		}

		// Filling the matrix
		for (int i = 1; i <= N; i++) {
			for (int j = 1; j <= L; j++) {
				// If it's a '?', then we need to add to dpm[i][j]
				// size * dpm[i - 1][j] + dpm[i - 1][j - 1], and if
				// the size is 0, we multiply by 1
				if (K.charAt(i - 1) == '?') {
					if (size != 0) {
						int sum = 0;
						for (int k = 0; k < size; k++) {
							sum = (sum + dpm[i - 1][j]) % MODULO;
						}
						dpm[i][j] = (sum + dpm[i - 1][j - 1]) % MODULO;
					} else {
						dpm[i][j] = (dpm[i - 1][j] + dpm[i - 1][j - 1])  % MODULO;
					}
					continue;
				}

				// If it's not a '?', we verify if the characters match
				// and if yes, we add the two positions , if not we have
				// the same number of substrings as dpm[i - 1][j]
				if (K.charAt(i - 1) == S.charAt(j - 1)) {
					dpm[i][j] = (dpm[i - 1][j] + dpm[i - 1][j - 1])  % MODULO;
				} else {
					dpm[i][j] = dpm[i - 1][j];
				}
			}
		}

		// Opening the file to write the output
		File outputFile = new File("crypto.out");
		FileWriter writer = new FileWriter(outputFile);

		// Writing the answer
		Integer answer = dpm[N][L] % MODULO;
		writer.write(answer.toString());

		// Closing the writer
		writer.close();
	}
}

#include <iostream>
