using namespace std;

int vec[100001][11];

#define isQuestionMark(c) (c == '?')
#define MOD 1000000007

// calculam numarul de litere distincte din stringul str
int countDistinctChars(string &str) {
    int arr[26] = {0}, ans = 0;

    for(int i = 0; i < str.size(); i++) {
        arr[str[i] - 'a']++;
    }

    for(int i = 0; i < 26; i++) {
        if(arr[i] > 0) {
            ans++;
        }
    }

    return ans;
}

// initializeaza prima coloana
void initFirstColumn(string& k, int klen, int d) {
    vec[0][0] = 1;

    for(int i = 1; i < klen; i++) {
        vec[i][0] = vec[i-1][0];
        if (isQuestionMark(k[i - 1])) {
            vec[i][0] = (1LL * d * vec[i - 1][0]) % MOD;
        }
    }
}

// functie ajutatoare pentru calcularea valorii elementului de pe pozitia i j
int helper(string &key, string &str, int d, int i, int j, bool isQuestionMark) {
    if (key[i - 1] == str[j - 1]) {
        return (1LL * (vec[i - 1][j - 1] + vec[i - 1][j])) % MOD;
    }
    if (isQuestionMark) {
        return (vec[i - 1][j - 1] + 1LL * d * vec[i - 1][j]) % MOD;
    }
    return vec[i - 1][j];
}

// folosesc o dinamica pentru a calcula numarul de aparitii ale sirului format din primele
// j litere ale sirului 2 in sirul format din primele i litere ale primului sir
int getCrypto(string &k, string &s, int n, int m, int d) {
    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= m; j++) {
            vec[i][j] = helper(k, s, d, i, j, isQuestionMark(k[i - 1]));
        }
    }
    return vec[n][m];
}

